      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const tasksService = require('./service');

router.get('/:projectId/tasks', (req, res) => {
  const { status } = req.query;
  const tasks = tasksService.getTasks(req.params.projectId, status);
  if (!tasks) return sendError(res, 404, 'NOT_FOUND', 'Tasks not found');
  res.json({ tasks });
});

router.patch('/:projectId/tasks/:taskId', (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const updatedTask = tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!updatedTask) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  res.json({ task: updatedTask });
});

module.exports = router;"
