      "content": "const projects = new Map();

export function addProject(name) {
  if (!name) throw new Error('Name is required');
  const id = randomUUID();
  projects.set(id, { id, name });
  return { id, name };
}

export function getProject(projectId) {
  return projects.get(projectId);
}
